local Ballistics = {}

local function atan2(y, x)
    if math.atan2 then return math.atan2(y, x) end
    return math.atan(y, x)
end

local function quatFromAxisAngle(axis, angle)
    local halfAngle = angle * 0.5
    local s = math.sin(halfAngle)
    local w = math.cos(halfAngle)
    -- Assuming normalized axis
    return Quaterniond:new(axis.x * s, axis.y * s, axis.z * s, w)
end

-- ==========================================
-- Matrix3d Implementation
-- ==========================================

local Matrix3d = {}
Matrix3d.__index = Matrix3d

function Matrix3d:new(m00, m01, m02, m10, m11, m12, m20, m21, m22)
    local self = setmetatable({}, Matrix3d)
    self.m00 = m00 or 0; self.m01 = m01 or 0; self.m02 = m02 or 0
    self.m10 = m10 or 0; self.m11 = m11 or 0; self.m12 = m12 or 0
    self.m20 = m20 or 0; self.m21 = m21 or 0; self.m22 = m22 or 0
    return self
end

function Matrix3d:zero()
    self.m00 = 0; self.m01 = 0; self.m02 = 0
    self.m10 = 0; self.m11 = 0; self.m12 = 0
    self.m20 = 0; self.m21 = 0; self.m22 = 0
    return self
end

function Matrix3d:identity()
    self:zero()
    self.m00 = 1
    self.m11 = 1
    self.m22 = 1
    return self
end

function Matrix3d:copy()
    return Matrix3d:new(
        self.m00, self.m01, self.m02,
        self.m10, self.m11, self.m12,
        self.m20, self.m21, self.m22
    )
end

function Matrix3d:determinant()
    return self.m00 * (self.m11 * self.m22 - self.m12 * self.m21) +
           self.m01 * (self.m12 * self.m20 - self.m10 * self.m22) +
           self.m02 * (self.m10 * self.m21 - self.m11 * self.m20)
end

function Matrix3d:invert()
    local det = self:determinant()
    if math.abs(det) < 1e-12 then
        error("Matrix is singular")
    end
    local invDet = 1.0 / det

    local nm00 = (self.m11 * self.m22 - self.m12 * self.m21) * invDet
    local nm01 = (self.m02 * self.m21 - self.m01 * self.m22) * invDet
    local nm02 = (self.m01 * self.m12 - self.m02 * self.m11) * invDet

    local nm10 = (self.m12 * self.m20 - self.m10 * self.m22) * invDet
    local nm11 = (self.m00 * self.m22 - self.m02 * self.m20) * invDet
    local nm12 = (self.m02 * self.m10 - self.m00 * self.m12) * invDet

    local nm20 = (self.m10 * self.m21 - self.m11 * self.m20) * invDet
    local nm21 = (self.m01 * self.m20 - self.m00 * self.m21) * invDet
    local nm22 = (self.m00 * self.m11 - self.m01 * self.m10) * invDet

    return Matrix3d:new(nm00, nm01, nm02, nm10, nm11, nm12, nm20, nm21, nm22)
end

-- ==========================================
-- Math Utilities
-- ==========================================

local function radianReset(angle)
    while angle <= -math.pi do angle = angle + 2 * math.pi end
    while angle > math.pi do angle = angle - 2 * math.pi end
    return angle
end

local function clamp(val, limit)
    return math.max(-limit, math.min(limit, val))
end

