local StandardBallisticUtils = {}

function StandardBallisticUtils.dropDistance(t, vy, c, g)
    vy = vy / 20
    t = t * 20
    local a = 1 - c
    local B = g / c
    return (vy - B) * (1 - a^t) / c + B * t
end

function StandardBallisticUtils.flatDistance(v, t, c)
    v = v / 20
    t = t * 20
    local a = 1 - c
    local b = 1
    return b * v * (1 - a^t) / c
end

